import heapq
from collections import defaultdict

def agent_step(state, history):
    def heuristic(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def a_star_search(start, goal, walls, blocks, known_obstacles, all_positions):
        # Enhanced A* to handle pushable blocks by simulating pushes
        frontier = []
        heapq.heappush(frontier, (0, start))
        came_from = {}
        cost_so_far = {}
        came_from[start] = None
        cost_so_far[start] = 0

        while frontier:
            _, current = heapq.heappop(frontier)

            if current == goal:
                break

            for dx, dy in [(-3, 0), (3, 0), (0, -3), (0, 3)]:  # Left, Right, Up, Down
                next_step = (current[0] + dx, current[1] + dy)
                if next_step in walls:
                    continue  # Wall blocks completely
                elif next_step in blocks:
                    # Simulate pushing the block
                    push_next = (next_step[0] + dx, next_step[1] + dy)
                    if push_next not in walls and push_next not in blocks and push_next in all_positions:
                        # Check if this push has historically succeeded
                        if not any(h['moved'] and get_move_direction(current, next_step) in h['action']['action'] for h in history if tuple(h['state']['player']['position']) == next_step):
                            continue  # Skip if history suggests this push fails
                        new_cost = cost_so_far[current] + 2  # Higher cost for pushing
                        if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                            cost_so_far[next_step] = new_cost
                            priority = new_cost + heuristic(goal, next_step)
                            heapq.heappush(frontier, (priority, next_step))
                            came_from[next_step] = current
                elif next_step not in known_obstacles:
                    new_cost = cost_so_far[current] + 1
                    if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                        cost_so_far[next_step] = new_cost
                        priority = new_cost + heuristic(goal, next_step)
                        heapq.heappush(frontier, (priority, next_step))
                        came_from[next_step] = current

        if goal not in came_from:
            return None  # No path found
        current = goal
        path = []
        while current != start:
            path.append(current)
            current = came_from[current]
        path.reverse()
        return path

    def get_move_direction(from_pos, to_pos):
        if from_pos[0] < to_pos[0]:
            return "MOVE_RIGHT"
        elif from_pos[0] > to_pos[0]:
            return "MOVE_LEFT"
        elif from_pos[1] < to_pos[1]:
            return "MOVE_DOWN"
        elif from_pos[1] > to_pos[1]:
            return "MOVE_UP"
        return None

    def analyze_history(history):
        failure_counts = defaultdict(int)
        success_counts = defaultdict(int)
        known_obstacles = set()
        consecutive_stuck = 0
        for turn in reversed(history):
            if not turn.get("moved", False):
                consecutive_stuck += 1
                if "action" in turn and turn["action"].get("action"):
                    action = turn["action"]["action"]
                    failure_counts[action] += 1
                    prev_pos = tuple(turn["state"]["player"]["position"])
                    if action == "MOVE_RIGHT":
                        known_obstacles.add((prev_pos[0] + 3, prev_pos[1]))
                    elif action == "MOVE_LEFT":
                        known_obstacles.add((prev_pos[0] - 3, prev_pos[1]))
                    elif action == "MOVE_UP":
                        known_obstacles.add((prev_pos[0], prev_pos[1] - 3))
                    elif action == "MOVE_DOWN":
                        known_obstacles.add((prev_pos[0], prev_pos[1] + 3))
            else:
                if "action" in turn and turn["action"].get("action"):
                    action = turn["action"]["action"]
                    success_counts[action] += 1
                consecutive_stuck = 0
        return failure_counts, success_counts, consecutive_stuck, known_obstacles

    player_pos = tuple(state["player"]["position"])
    goals = state["objects"]["goals"]
    walls = {tuple(wall["position"]) for wall in state["objects"]["walls"]}
    blocks = {tuple(block["position"]) for block in state["objects"]["blocks"]}
    all_positions = set()  # Placeholder; in practice, derive from grid bounds if available

    failure_counts, success_counts, consecutive_stuck, known_obstacles = analyze_history(history)

    # Update known obstacles with heuristic hints
    if state["movement"]["right_blocked"]:
        known_obstacles.add((player_pos[0] + 3, player_pos[1]))
    if state["movement"]["left_blocked"]:
        known_obstacles.add((player_pos[0] - 3, player_pos[1]))
    if state["movement"]["up_blocked"]:
        known_obstacles.add((player_pos[0], player_pos[1] - 3))
    if state["movement"]["down_blocked"]:
        known_obstacles.add((player_pos[0], player_pos[1] + 3))

    if goals and state["resources"]["steps_remaining"] > 0:
        goal_pos = tuple(goals[0]["position"])
        path = a_star_search(player_pos, goal_pos, walls, blocks, known_obstacles, all_positions)

        if path:
            next_step = path[0]
            move_direction = get_move_direction(player_pos, next_step)
            if move_direction and success_counts.get(move_direction, 0) > failure_counts.get(move_direction, 0):
                return {"action": move_direction}

        if consecutive_stuck >= 3:
            selectables = state["objects"]["selectables"]
            other_selectables = [sel for sel in selectables if tuple(sel["position"]) != player_pos and heuristic(tuple(sel["position"]), goal_pos) < heuristic(player_pos, goal_pos)]
            if other_selectables:
                best_selectable = min(other_selectables, key=lambda sel: heuristic(tuple(sel["position"]), goal_pos))
                return {"action": "CLICK", "target_position": best_selectable["position"]}

        # Fallback to direction with highest success rate
        directions = ["MOVE_RIGHT", "MOVE_LEFT", "MOVE_UP", "MOVE_DOWN"]
        best_direction = max(directions, key=lambda d: success_counts.get(d, 0) - failure_counts.get(d, 0))
        return {"action": best_direction}

    # Ultimate fallback
    cycle = ["MOVE_RIGHT", "MOVE_DOWN", "MOVE_LEFT", "MOVE_UP"]
    step = len(history)
    return {"action": cycle[step % len(cycle)]}
